#!/usr/bin/env python3
from __future__ import annotations

import argparse
import json
import os
import tempfile
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]
REPORT_DIR = ROOT / "research" / "reports"


def atomic_write_text(path: Path, content: str, *, encoding: str = "utf-8") -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with tempfile.NamedTemporaryFile("w", encoding=encoding, dir=str(path.parent), delete=False) as handle:
        handle.write(content)
        tmp_path = Path(handle.name)
    os.replace(tmp_path, path)


def load_json(path: Path) -> dict[str, Any]:
    return json.loads(path.read_text(encoding="utf-8"))


def fmt_money(value: Any) -> str:
    if value in (None, ""):
        return "-"
    return f"{float(value):,.0f}"


def fmt_pct(value: Any) -> str:
    if value in (None, ""):
        return "-"
    return f"{float(value):.2f}%"


def short_sources(paths: list[str]) -> str:
    return ", ".join(Path(item).name for item in paths if item) or "-"


def holding_compact(item: dict[str, Any]) -> str:
    label = f"{item.get('ts_code') or '-'} {item.get('name') or '-'}"
    bits: list[str] = []
    if item.get("weight_pct") not in (None, ""):
        bits.append(f"{float(item['weight_pct']):.2f}%")
    if item.get("pnl_pct") not in (None, ""):
        bits.append(fmt_pct(item.get("pnl_pct")))
    if item.get("buy_date"):
        bits.append(f"买入{item['buy_date']}")
    return f"{label}({ ' / '.join(bits) })" if bits else label


def build_lines(payload: dict[str, Any]) -> list[str]:
    lines = [
        f"【每日量化分析】{payload.get('trade_date')}",
        f"总状态：{payload.get('overall_status')}",
        f"交易状态：{((payload.get('trading') or {}).get('trading_status')) or '-'} / {((payload.get('trading') or {}).get('trading_reason')) or '-'}",
        f"治理门禁：{((payload.get('governance') or {}).get('status')) or '-'}",
    ]

    profiles = payload.get("profiles") or []
    if profiles:
        lines.append("主组合：")
        for row in profiles[:3]:
            lines.append(
                f"- {row.get('profile_name') or row.get('profile_slug')}: 净值 {fmt_money(row.get('nav'))}，总收益 {row.get('total_return_pct')}%，状态 {row.get('status')}"
            )

    breadth_profiles = payload.get("breadth_profiles") or []
    if breadth_profiles:
        lines.append("Breadth：")
        for row in breadth_profiles[:2]:
            lines.append(
                f"- {row.get('profile_slug')}: 净值 {fmt_money(row.get('nav'))}，总收益 {row.get('total_return_pct')}%"
            )

    profile_holdings = payload.get("profile_holdings") or []
    if profile_holdings:
        lines.append("模拟盘持仓：")
        for entry in profile_holdings:
            holdings = entry.get("holdings") or []
            holdings_text = "；".join(holding_compact(item) for item in holdings) if holdings else "空仓"
            lines.append(
                f"- {entry.get('profile_name') or entry.get('profile_slug')}: {entry.get('source_label') or '单一模拟盘'} / {entry.get('position_count', 0)}持仓 / 来源 {short_sources(entry.get('source_files') or [])}"
            )
            lines.append(f"  {holdings_text}")

    candidate_summary = payload.get("candidate_summary") or {}
    candidate_source = payload.get("candidate_source_summary") or {}
    lines.append(
        f"候选：执行买入 {candidate_summary.get('buy_candidates', '-')}, 研究候选 {candidate_summary.get('research_buy_candidates', '-')}, 卖出风险 {candidate_summary.get('sell_candidates', '-')}"
    )
    lines.append(
        f"候选来源：{candidate_source.get('source_label') or '-'} / {', '.join(candidate_source.get('source_file_names') or []) or '-'} / 策略 {', '.join(candidate_source.get('strategy_ids') or []) or '-'}"
    )

    watchlist = payload.get("acceptance_watchlist") or []
    if watchlist:
        lines.append("未闭环验收：")
        for item in watchlist[:3]:
            lines.append(f"- {item.get('summary')}")

    freshness = payload.get("data_freshness") or {}
    if freshness.get("missing_required_inputs") or freshness.get("mismatched_required_inputs"):
        lines.append(
            f"数据新鲜度告警：missing={freshness.get('missing_required_inputs') or []} mismatch={freshness.get('mismatched_required_inputs') or []}"
        )

    lines.append(f"详报：research/reports/daily_quant_analysis_skill_{payload.get('trade_date_tag')}.md")
    return lines


def main() -> None:
    parser = argparse.ArgumentParser(description="Render Feishu summary text from structured daily quant analysis JSON")
    parser.add_argument("--input", default=str(REPORT_DIR / "daily_quant_analysis_skill_latest.json"))
    args = parser.parse_args()

    payload = load_json(Path(args.input))
    trade_date_tag = str(payload.get("trade_date_tag") or "latest")
    text = "\n".join(build_lines(payload)).strip() + "\n"

    outputs = [
        REPORT_DIR / f"daily_quant_analysis_feishu_{trade_date_tag}.txt",
        REPORT_DIR / "daily_quant_analysis_feishu_latest.txt",
    ]
    for path in outputs:
        atomic_write_text(path, text)
    print(str(outputs[0]))


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
from __future__ import annotations

import argparse
import hashlib
import json
import shutil
import subprocess
from datetime import datetime
from pathlib import Path
from typing import Any

from investment_research_health_snapshot import build_health_snapshot, build_ths_alert_line, latest_health_probe_for_date

WORKSPACE = Path.home() / ".openclaw" / "workspace"
REPORT_DIR = WORKSPACE / "research" / "reports"
CONFIG_FILE = WORKSPACE / "config" / "investment_research_delivery_v1.json"
STATE_FILE = WORKSPACE / "memory" / "investment_research_delivery_state.json"
OPENCLAW_BIN_CANDIDATES = [
    str(Path.home() / ".local" / "share" / "fnm" / "aliases" / "default" / "bin" / "openclaw"),
    shutil.which("openclaw") or "",
    "openclaw",
]

MEETING_LABELS = {
    "morning": "盘前会",
    "midday": "午盘巡检",
    "close": "收盘复盘",
    "night": "夜间研究会",
}

MEETING_EMOJIS = {
    "morning": "🌅",
    "midday": "☀️",
    "close": "📘",
    "night": "🌙",
}

STATUS_LABELS = {
    "healthy": "健康",
    "offhours_guarded": "非交易时段观察",
    "watch_guarded": "警戒观察",
    "degraded": "降级",
    "normal": "正常",
    "cautious": "谨慎",
    "observe_defensive": "防守观察",
    "halt": "暂停",
    "ok": "正常",
    "fallback": "已回退",
    "failed": "部分失败",
    "unavailable": "不可用",
    "unknown": "未知",
    "fresh": "今日已刷新",
    "pending_today_refresh": "待今日刷新",
    "stale": "已过期",
    "missing": "缺失",
}


def now_str() -> str:
    return datetime.now().strftime("%Y-%m-%d %H:%M:%S")


def default_date_tag() -> str:
    return datetime.now().strftime("%Y%m%d")


def load_json(path: Path) -> dict[str, Any]:
    if not path.exists():
        return {}
    try:
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def write_json(path: Path, payload: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")


def read_text(path: Path) -> str:
    if not path.exists():
        return ""
    return path.read_text(encoding="utf-8")


def cn_status(value: Any) -> str:
    if value is None or value == "":
        return "-"
    return STATUS_LABELS.get(str(value), str(value))


def cn_text(value: Any) -> str:
    if value is None or value == "":
        return "-"
    text = str(value)
    replacements = {
        "public_source_divergence>": "公开网页源存在价差分歧 > ",
        "normal模式": "正常模式",
        "FULL_HALT": "全市场暂停新增",
        "BUY_HALT": "暂停买入",
        "strict precheck": "严格盘前检查",
        "watch_guarded": "警戒观察",
        "offhours_guarded": "非交易时段观察",
        "healthy": "健康",
        "degraded": "降级",
    }
    for old, new in replacements.items():
        text = text.replace(old, new)
    return text


def resolve_openclaw_bin() -> str:
    for candidate in OPENCLAW_BIN_CANDIDATES:
        if candidate and Path(candidate).exists():
            return candidate
    for candidate in OPENCLAW_BIN_CANDIDATES:
        if candidate:
            return candidate
    return "openclaw"


def run_cmd(cmd: list[str], timeout: int = 120) -> tuple[int, str, str]:
    try:
        proc = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout)
        return proc.returncode, proc.stdout or "", proc.stderr or ""
    except FileNotFoundError as exc:
        return 127, "", str(exc)
    except subprocess.TimeoutExpired as exc:
        return 124, exc.stdout or "", exc.stderr or f"timeout after {timeout}s"


def selected_targets(config: dict[str, Any]) -> list[tuple[str, dict[str, Any]]]:
    targets = config.get("targets", {})
    mode = str(config.get("deliveryMode") or "dm_and_group")
    ordered_names: list[str]
    if mode == "dm":
        ordered_names = ["dm"]
    elif mode == "group":
        ordered_names = ["group"]
    else:
        ordered_names = ["dm", "group"]

    result: list[tuple[str, dict[str, Any]]] = []
    for name in ordered_names:
        payload = targets.get(name)
        if isinstance(payload, dict) and payload.get("enabled", True):
            result.append((name, payload))
    if result:
        return result

    for name, payload in targets.items():
        if isinstance(payload, dict) and payload.get("enabled", True):
            result.append((str(name), payload))
    return result


def compact_watchlist(items: list[Any], limit: int = 5) -> list[str]:
    result: list[str] = []
    for item in items[:limit]:
        if isinstance(item, dict):
            display = item.get("display") or item.get("ticker") or item.get("name")
            if display:
                result.append(str(display))
        elif item:
            result.append(str(item))
    return result


def compact_sell_review(items: list[Any], limit: int = 5) -> list[str]:
    result: list[str] = []
    for item in items[:limit]:
        if isinstance(item, dict):
            display = item.get("display") or item.get("ticker") or item.get("name")
            reason = item.get("reason") or item.get("action")
            if display and reason:
                result.append(f"{display} | {reason}")
            elif display:
                result.append(str(display))
        elif item:
            result.append(str(item))
    return result


def resolve_health_snapshot(date_tag: str, bundle: dict[str, Any], control_tower: dict[str, Any]) -> dict[str, Any]:
    health_scope, health_probe, health_path = latest_health_probe_for_date(REPORT_DIR, date_tag)
    if health_probe:
        return build_health_snapshot(health_scope, health_probe, health_path)
    health_snapshot = control_tower.get("health_probe", {}) if isinstance(control_tower.get("health_probe"), dict) else {}
    if health_snapshot:
        return health_snapshot
    bundle_probe = bundle.get("data_source_health", {}) if isinstance(bundle.get("data_source_health"), dict) else {}
    if bundle_probe:
        return build_health_snapshot(bundle_probe.get("scope"), bundle_probe, None)
    return {}


def should_include_execution_review_summary(meeting_type: str, trade_card: dict[str, Any]) -> bool:
    if meeting_type not in {"close", "night"}:
        return False
    entries = trade_card.get("execution_review_entries", [])
    if not entries or not isinstance(entries[0], dict):
        return False
    review_item = entries[0]
    if review_item.get("reason") == "holding_outside_trade_loop":
        return False
    if review_item.get("primary_attribution_label") == "holding_without_strategy_exit":
        return False
    if review_item.get("stage") == "sell_review" and not trade_card.get("sell_review_list"):
        return False
    return True


def build_message(
    meeting_type: str,
    date_tag: str,
    trade_card: dict[str, Any],
    bundle: dict[str, Any],
    health_snapshot: dict[str, Any],
) -> str:
    watchlist = compact_watchlist(trade_card.get("watchlist", []))
    sell_review = compact_sell_review(trade_card.get("sell_review_list", []))
    event_watch = bundle.get("event_watch", {}) if isinstance(bundle.get("event_watch"), dict) else {}
    ths = health_snapshot.get("ths_market", {}) if isinstance(health_snapshot.get("ths_market"), dict) else {}
    paper_freshness = trade_card.get("paper_execution_freshness", {}) if isinstance(trade_card.get("paper_execution_freshness"), dict) else {}
    risk_text = "偏防守" if trade_card.get("risk_off") else "条件化推进"
    watchlist_text = "、".join(watchlist) if watchlist else str(trade_card.get("watchlist_reason") or "暂无")
    sell_review_text = "、".join(sell_review) if sell_review else str(trade_card.get("sell_review_reason") or "暂无")
    alert_line = build_ths_alert_line(health_snapshot)

    lines: list[str] = []
    if alert_line:
        lines.append(f"[THS告警] {cn_text(alert_line)}")

    lines.extend([
        f"{MEETING_EMOJIS.get(meeting_type, '📊')} 模拟交易提示｜{MEETING_LABELS.get(meeting_type, meeting_type)}｜{date_tag}",
        f"- 风险状态：{risk_text}",
        f"- 模拟买入观察：{watchlist_text}",
        f"- 模拟卖出复核：{sell_review_text}",
